// Merge all config and agent prompts into a single object
// All 4 fetch results are now available via the chained Merge nodes
const allItems = $input.all();

// Find each config by checking the response structure
let sourcesConfig, thresholdsConfig, classifyPrompt, summarizePrompt;

for (const item of allItems) {
  const data = item.json;
  if (data.sources) sourcesConfig = data;
  else if (data.ingestion || data.publishing || data.runtime) thresholdsConfig = data;
  else if (data.content && data.name === 'classify') classifyPrompt = data;
  else if (data.content && data.name === 'summarize') summarizePrompt = data;
  else if (data.content) {
    // Fallback: check content for agent type hints
    if (data.content.includes('freedom_relevance_score')) classifyPrompt = data;
    else summarizePrompt = data;
  }
}

return [{
  json: {
    _sources: sourcesConfig || {},
    _thresholdsConfig: thresholdsConfig || {},
    _agents: {
      classify: classifyPrompt?.content || '',
      summarize: summarizePrompt?.content || ''
    }
  }
}];

// Load sources from API config and agent prompts
// Reads from merged config node output

const merged = $('Merge Config & Agents').first().json;
const sourcesConfig = merged._sources;
const thresholdsConfig = merged._thresholdsConfig;
const agents = merged._agents;

// Store thresholds in first item for reference by downstream nodes
// Include runtime section for stub/real mode toggle
const thresholds = {
  runtime: thresholdsConfig.runtime || { use_stubs: true },
  ingestion: thresholdsConfig.ingestion || { relevance_threshold: 50 },
  publishing: thresholdsConfig.publishing || { auto_publish_relevance: 70, auto_publish_credibility: 60 },
  ideas: thresholdsConfig.ideas || { min_relevance_for_idea: 80 }
};

// Get sources from config
const sources = sourcesConfig.sources || [];

// Filter to enabled sources only
const enabledSources = sources.filter(s => s.enabled);

if (enabledSources.length === 0) {
  console.log('Warning: No enabled sources found in config');
  return [];
}

console.log(`Loaded ${enabledSources.length} sources from config`);
console.log(`Loaded agent prompts: classify (${agents.classify?.length || 0} chars), summarize (${agents.summarize?.length || 0} chars)`);

// Return each source as a separate item for parallel processing
// Include thresholds and agent prompts in each item so downstream nodes can access them
return enabledSources.map(source => ({ 
  json: {
    ...source,
    _thresholds: thresholds,
    _agents: agents
  }
}));

// Process RSS items from feed
const items = $input.all();
const sourceInfo = $('Load Sources').first().json;

// Handle fetch errors
if (!items || items.length === 0) {
  console.log(`No items from ${sourceInfo.name}`);
  return [];
}

// Limit items per source (rate limiting)
const maxItems = 20;
const processItems = items.slice(0, maxItems);

return processItems.map(item => {
  const data = item.json;
  return {
    json: {
      // Source metadata
      sourceName: sourceInfo.name,
      sourceUrl: sourceInfo.url,
      sourceTier: sourceInfo.tier,
      sourceTags: sourceInfo.tags,
      platform: 'rss',

      // Thresholds and agents from config
      _thresholds: sourceInfo._thresholds,
      _agents: sourceInfo._agents,

      // Item data
      itemUrl: data.link || data.guid || '',
      title: data.title || '',
      content: data.content || data.description || data['content:encoded'] || '',
      author: data.creator || data.author || sourceInfo.name,
      publishedAt: data.pubDate || data.isoDate || new Date().toISOString(),

      // Will be computed
      contentHash: null,
      extractedText: null
    }
  };
}).filter(item => item.json.itemUrl && item.json.content);

// Extract clean text from HTML content
const item = $input.first().json;

// Strip HTML tags for clean text extraction
function stripHtml(html) {
  if (!html) return '';
  return html
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

const extractedText = stripHtml(item.content);

// Pass through _agents for downstream use
return [{
  json: {
    ...item,
    extractedText: extractedText.substring(0, 50000)
  }
}];

// Evaluate duplicate check result and merge with original data
const duplicateResult = $input.all();
const originalData = $('Compute Hash').first().json;

// Postgres returns empty array if no rows found
// If we got any rows back, it's a duplicate
const isDuplicate = duplicateResult.length > 0 && duplicateResult[0].json && duplicateResult[0].json.id;

return [{
  json: {
    ...originalData,
    isNew: !isDuplicate,
    duplicateId: isDuplicate ? duplicateResult[0].json.id : null
  }
}];

// STUB: Classifier Agent
// Simulates Claude API response format for classification
// Replace with real HTTP Request to Claude API when ready

const sourceItem = $('Insert Source Item').first().json;
const metadata = $('Evaluate Duplicate').first().json;
const thresholds = metadata._thresholds || {};
const text = sourceItem.extracted_text || '';
const textLower = text.toLowerCase();

// Get relevance threshold from config
const relevanceThreshold = thresholds.ingestion?.relevance_threshold || 50;

// Simple keyword-based classification for testing
const topics = [];

if (textLower.includes('bitcoin') || textLower.includes('btc') || textLower.includes('satoshi')) {
  topics.push('bitcoin');
}
if (textLower.includes('privacy') || textLower.includes('encryption') || textLower.includes('encrypted')) {
  topics.push('privacy');
}
if (textLower.includes('censorship') || textLower.includes('blocked') || textLower.includes('banned')) {
  topics.push('censorship-resistance');
}
if (textLower.includes('surveillance') || textLower.includes('tracking') || textLower.includes('monitoring')) {
  topics.push('surveillance');
}
if (textLower.includes('activist') || textLower.includes('protest') || textLower.includes('dissent')) {
  topics.push('activism');
}
if (textLower.includes('identity') || textLower.includes('kyc') || textLower.includes('anonymous')) {
  topics.push('identity');
}
if (textLower.includes('payment') || textLower.includes('transaction') || textLower.includes('transfer')) {
  topics.push('payments');
}
if (textLower.includes('messaging') || textLower.includes('signal') || textLower.includes('communication')) {
  topics.push('comms');
}
if (textLower.includes('zero knowledge') || textLower.includes('zk-') || textLower.includes('zkp')) {
  topics.push('zk');
}
if (textLower.includes('sovereign') || textLower.includes('self-custody') || textLower.includes('freedom')) {
  topics.push('sovereignty');
}

// Default topic if none found
if (topics.length === 0) {
  topics.push('sovereignty');
}

// Score based on keyword density and source tier
const tier = metadata.sourceTier || 2;
const keywordCount = topics.length;
const baseRelevance = Math.min(40 + (keywordCount * 15), 95);
const tierBonus = tier === 1 ? 10 : 0;
const freedomRelevanceScore = Math.min(baseRelevance + tierBonus, 100);

// Credibility based on source tier
const credibilityScore = tier === 1 ? 75 : tier === 2 ? 60 : 45;

// Check for safety concerns
const safetyConcern = textLower.includes('location') && 
  (textLower.includes('activist') || textLower.includes('dissident'));

// Use threshold from config
const shouldSummarize = freedomRelevanceScore >= relevanceThreshold;

const classification = {
  topics: topics.slice(0, 5),
  freedom_relevance_score: freedomRelevanceScore,
  credibility_score: credibilityScore,
  geo: [],
  safety_concern: safetyConcern,
  reasoning: `Stub classification based on ${keywordCount} topic keywords. Tier ${tier} source.`,
  key_entities: [],
  should_summarize: shouldSummarize
};

// Return in Claude API response format for easy swap later
return [{
  json: {
    content: [{
      type: 'text',
      text: JSON.stringify(classification)
    }],
    // Pass through source item data
    _sourceItemId: sourceItem.id,
    _sourceItemUrl: sourceItem.url,
    _extractedText: sourceItem.extracted_text,
    _metadata: metadata,
    _thresholds: thresholds,
    _agents: metadata._agents
  }
}];

// Process real Claude API response and add pass-through data
const claudeResponse = $input.first().json;
const sourceItem = $('Insert Source Item').first().json;
const metadata = $('Evaluate Duplicate').first().json;
const thresholds = metadata._thresholds || {};

// Return in same format as stub for Parse Classification compatibility
return [{
  json: {
    content: claudeResponse.content,
    _sourceItemId: sourceItem.id,
    _sourceItemUrl: sourceItem.url,
    _extractedText: sourceItem.extracted_text,
    _metadata: metadata,
    _thresholds: thresholds,
    _agents: metadata._agents
  }
}];

