// Parse classification result from Claude API format
const input = $input.first().json;
let classification;

try {
  let text = input.content[0].text;

  // Strip markdown code blocks if present (Claude often wraps JSON in ```json...```)
  text = text.trim();
  if (text.startsWith('```')) {
    // Remove opening fence (```json or ```)
    text = text.replace(/^```(?:json)?\s*\n?/, '');
    // Remove closing fence
    text = text.replace(/\n?```\s*$/, '');
  }

  classification = JSON.parse(text.trim());
} catch (e) {
  // Fallback if parsing fails
  console.log('Parse Classification error:', e.message);
  console.log('Raw text:', input.content?.[0]?.text?.substring(0, 200));
  classification = {
    topics: ['sovereignty'],
    freedom_relevance_score: 30,
    credibility_score: 50,
    geo: [],
    safety_concern: false,
    reasoning: 'Failed to parse LLM response: ' + e.message,
    key_entities: [],
    should_summarize: false
  };
}

// Merge with source item data
return [{
  json: {
    sourceItemId: input._sourceItemId,
    sourceItemUrl: input._sourceItemUrl,
    extractedText: input._extractedText,
    metadata: input._metadata,
    classification,
    _thresholds: input._thresholds,
    _agents: input._agents
  }
}];

// Validate classification output against schema
const data = $input.first().json;
const classification = data.classification;
const errors = [];

// Valid topics enum
const validTopics = ['bitcoin', 'zk', 'censorship-resistance', 'comms', 'payments', 'identity', 'privacy', 'surveillance', 'activism', 'sovereignty'];

// Validate topics
if (!Array.isArray(classification.topics)) {
  errors.push('topics must be an array');
} else {
  if (classification.topics.length < 1) errors.push('topics must have at least 1 item');
  if (classification.topics.length > 5) errors.push('topics must have at most 5 items');
  for (const topic of classification.topics) {
    if (!validTopics.includes(topic)) {
      errors.push(`Invalid topic: ${topic}. Must be one of: ${validTopics.join(', ')}`);
    }
  }
}

// Validate scores
if (typeof classification.freedom_relevance_score !== 'number' || classification.freedom_relevance_score < 0 || classification.freedom_relevance_score > 100) {
  errors.push('freedom_relevance_score must be an integer between 0 and 100');
}
if (typeof classification.credibility_score !== 'number' || classification.credibility_score < 0 || classification.credibility_score > 100) {
  errors.push('credibility_score must be an integer between 0 and 100');
}

// Validate geo
if (!Array.isArray(classification.geo)) {
  errors.push('geo must be an array');
}

// Validate safety_concern
if (typeof classification.safety_concern !== 'boolean') {
  errors.push('safety_concern must be a boolean');
}

// Validate should_summarize
if (typeof classification.should_summarize !== 'boolean') {
  errors.push('should_summarize must be a boolean');
}

// Log validation result
if (errors.length > 0) {
  console.log('Classification validation errors:', errors);
}

return [{
  json: {
    ...data,
    _validationErrors: errors,
    _validationPassed: errors.length === 0
  }
}];

// Check if content meets relevance threshold from config
const data = $input.first().json;
const thresholds = data._thresholds || {};
const relevanceThreshold = thresholds.ingestion?.relevance_threshold || 50;

const score = data.classification.freedom_relevance_score;
const shouldSummarize = data.classification.should_summarize;

// Content meets threshold if score >= config threshold AND should_summarize is true
const meetsThreshold = score >= relevanceThreshold && shouldSummarize;

// Pass through all data including _agents
return [{
  json: {
    ...data,
    meetsThreshold,
    usedThreshold: relevanceThreshold
  }
}];

