// Process real Claude API response and add pass-through data for summarization
const claudeResponse = $input.first().json;
const applyThresholdData = $('Apply Threshold').first().json;

// Return in same format as stub for Parse Summary compatibility
return [{
  json: {
    content: claudeResponse.content,
    _sourceItemId: applyThresholdData.sourceItemId,
    _classification: applyThresholdData.classification,
    _sourceItemUrl: applyThresholdData.sourceItemUrl,
    _thresholds: applyThresholdData._thresholds,
    _agents: applyThresholdData._agents
  }
}];

// Parse summary and determine publish status using thresholds from config
const input = $input.first().json;
const thresholds = input._thresholds || {};
let summary;

try {
  let text = input.content[0].text;

  // Strip markdown code blocks if present (Claude often wraps JSON in ```json...```)
  text = text.trim();
  if (text.startsWith('```')) {
    // Remove opening fence (```json or ```)
    text = text.replace(/^```(?:json)?\s*\n?/, '');
    // Remove closing fence
    text = text.replace(/\n?```\s*$/, '');
  }

  summary = JSON.parse(text.trim());
} catch (e) {
  console.log('Parse Summary error:', e.message);
  console.log('Raw text:', input.content?.[0]?.text?.substring(0, 200));
  summary = {
    title: 'Parse Error',
    tldr: 'Failed to parse summary: ' + e.message,
    summary_bullets: ['Error processing content'],
    citations: [],
    deep_dive_markdown: null
  };
}

const classification = input._classification;

// Get thresholds from config
const autoPublishRelevance = thresholds.publishing?.auto_publish_relevance || 70;
const autoPublishCredibility = thresholds.publishing?.auto_publish_credibility || 60;

// Determine publish status based on gates from config
// Auto-publish: relevance >= config threshold AND credibility >= config threshold AND has citations
const canAutoPublish = 
  classification.freedom_relevance_score >= autoPublishRelevance &&
  classification.credibility_score >= autoPublishCredibility &&
  summary.citations.length > 0 &&
  !classification.safety_concern;

const status = canAutoPublish ? 'published' : 'queued';
const publishedAt = canAutoPublish ? new Date().toISOString() : null;

// Generate slug from title for URL
const slug = summary.title
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 60);

const publishedUrl = canAutoPublish 
  ? `https://libertas.fgu.tech/posts/${slug}`
  : null;

console.log(`Publishing gate: relevance ${classification.freedom_relevance_score} >= ${autoPublishRelevance}, credibility ${classification.credibility_score} >= ${autoPublishCredibility} => ${status}`);

return [{
  json: {
    sourceItemId: input._sourceItemId,
    sourceItemUrl: input._sourceItemUrl,
    title: summary.title,
    tldr: summary.tldr,
    summaryBullets: summary.summary_bullets,
    deepDiveMarkdown: summary.deep_dive_markdown,
    topics: classification.topics,
    geo: classification.geo,
    freedomRelevanceScore: classification.freedom_relevance_score,
    credibilityScore: classification.credibility_score,
    citations: summary.citations,
    status,
    publishedUrl,
    publishedAt,
    safetyConcern: classification.safety_concern,
    _usedThresholds: {
      autoPublishRelevance,
      autoPublishCredibility
    }
  }
}];

// Validate summary output against insight schema
const data = $input.first().json;
const errors = [];

// Validate title
if (typeof data.title !== 'string') {
  errors.push('title must be a string');
} else if (data.title.length > 120) {
  errors.push('title must be at most 120 characters');
}

// Validate tldr
if (typeof data.tldr !== 'string') {
  errors.push('tldr must be a string');
} else if (data.tldr.length > 280) {
  errors.push('tldr must be at most 280 characters');
}

// Validate summaryBullets
if (!Array.isArray(data.summaryBullets)) {
  errors.push('summaryBullets must be an array');
} else {
  if (data.summaryBullets.length < 5) errors.push('summaryBullets must have at least 5 items');
  if (data.summaryBullets.length > 10) errors.push('summaryBullets must have at most 10 items');
}

// Validate topics
const validTopics = ['bitcoin', 'zk', 'censorship-resistance', 'comms', 'payments', 'identity', 'privacy', 'surveillance', 'activism', 'sovereignty'];
if (!Array.isArray(data.topics)) {
  errors.push('topics must be an array');
} else {
  for (const topic of data.topics) {
    if (!validTopics.includes(topic)) {
      errors.push(`Invalid topic: ${topic}`);
    }
  }
}

// Validate scores
if (typeof data.freedomRelevanceScore !== 'number' || data.freedomRelevanceScore < 0 || data.freedomRelevanceScore > 100) {
  errors.push('freedomRelevanceScore must be an integer between 0 and 100');
}
if (typeof data.credibilityScore !== 'number' || data.credibilityScore < 0 || data.credibilityScore > 100) {
  errors.push('credibilityScore must be an integer between 0 and 100');
}

// Validate citations
if (!Array.isArray(data.citations)) {
  errors.push('citations must be an array');
}

// Validate status
const validStatuses = ['draft', 'queued', 'published', 'rejected'];
if (!validStatuses.includes(data.status)) {
  errors.push(`status must be one of: ${validStatuses.join(', ')}`);
}

// Log validation result
if (errors.length > 0) {
  console.log('Summary validation errors:', errors);
}

return [{
  json: {
    ...data,
    _summaryValidationErrors: errors,
    _summaryValidationPassed: errors.length === 0
  }
}];

// Build complete INSERT query with proper escaping
const data = $input.first().json;

function escapeStr(str) {
  if (str === null || str === undefined) return 'NULL';
  // Escape single quotes by doubling them
  return "'" + String(str).replace(/'/g, "''") + "'";
}

function formatPgArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  const escaped = arr.map(s => '"' + String(s).replace(/"/g, '\\"').replace(/'/g, "''") + '"');
  return "'{" + escaped.join(',') + "}'";
}

function formatUuidArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  return "'{" + arr.join(',') + "}'";
}

const query = `INSERT INTO insights (
  source_item_ids, title, tldr, summary_bullets, deep_dive_markdown,
  topics, geo, freedom_relevance_score, credibility_score, citations,
  status, published_url, published_at
) VALUES (
  ${formatUuidArray([data.sourceItemId])},
  ${escapeStr(data.title || 'Untitled')},
  ${escapeStr(data.tldr || '')},
  ${formatPgArray(data.summaryBullets || [])},
  ${data.deepDiveMarkdown ? escapeStr(data.deepDiveMarkdown) : 'NULL'},
  ${formatPgArray(data.topics || [])},
  ${formatPgArray(data.geo || [])},
  ${data.freedomRelevanceScore},
  ${data.credibilityScore},
  ${formatPgArray(data.citations || [])},
  ${escapeStr(data.status)},
  ${data.publishedUrl ? escapeStr(data.publishedUrl) : 'NULL'},
  ${data.publishedAt ? escapeStr(data.publishedAt) : 'NULL'}
) RETURNING id, title, status, published_url`;

return [{ json: { query, sourceData: data } }];

// Log skipped items (below threshold)
const data = $input.first().json;
console.log(`Skipped: ${data.sourceItemUrl} - Relevance: ${data.classification.freedom_relevance_score} (threshold: ${data.usedThreshold})`);

return [{
  json: {
    skipped: true,
    sourceItemId: data.sourceItemId,
    reason: 'Below relevance threshold',
    score: data.classification.freedom_relevance_score,
    threshold: data.usedThreshold
  }
}];

// Log duplicate items
console.log('Duplicate item detected, skipping');

return [{
  json: {
    skipped: true,
    reason: 'Duplicate content hash'
  }
}];

// Aggregate results from all branches
// This runs at the end to summarize the workflow execution

const allItems = $input.all();

let published = 0;
let queued = 0;
let skipped = 0;
let duplicates = 0;
let errors = 0;
let feedsPublished = 0;

for (const item of allItems) {
  const data = item.json;
  if (data.feedsCommitted) feedsPublished++;
  else if (data.status === 'published') published++;
  else if (data.status === 'queued') queued++;
  else if (data.skipped && data.reason === 'Duplicate content hash') duplicates++;
  else if (data.skipped) skipped++;
  else errors++;
}

const summary = {
  executedAt: new Date().toISOString(),
  results: {
    published,
    queued,
    skipped,
    duplicates,
    errors,
    feedsPublished,
    total: allItems.length
  }
};

console.log('Workflow A Summary:', JSON.stringify(summary, null, 2));

return [{ json: summary }];

// Generate RSS 2.0 feed from all published insights
const insights = $input.all().map(item => item.json).filter(i => i.id);
const newInsightData = $('Build Insight Query').first().json.sourceData;

// Site metadata
const siteUrl = 'https://libertas.fgu.tech';
const feedTitle = 'Libertas - Freedom Tech Signals';
const feedDescription = 'Curated insights on freedom technology: Bitcoin, privacy tools, censorship resistance, and digital sovereignty.';
const feedLanguage = 'en-us';
const buildDate = new Date().toUTCString();

// Helper to escape XML
function escapeXml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

// Generate RSS items
const items = insights.map(insight => {
  const pubDate = insight.published_at ? new Date(insight.published_at).toUTCString() : buildDate;
  const topics = Array.isArray(insight.topics) ? insight.topics : [];
  const categories = topics.map(t => `    <category>${escapeXml(t)}</category>`).join('\n');

  // Generate slug from title
